WITH target_plans(plan_id) AS (VALUES ('33aaa072-b90a-4f02-9310-7a9457a75244'::uuid),('a02f037e-390a-4e17-bee1-097dbb1765b2'::uuid),('8dbb5e67-3052-4f6e-a464-af3d7750ec13'::uuid),('6ea0b05c-33a0-4832-8658-4127c98ccc19'::uuid),('03f60aa4-42b4-4309-bd9d-f287d1d8cfc9'::uuid),('e8a515b2-dcd7-4771-927d-cf169fb87dd5'::uuid),('fa99e0c8-9309-4b2b-a34a-010574692a45'::uuid),('62d8c9d2-a8a8-4c52-a083-2b1a513b5fa0'::uuid),('5a4238d9-14bb-4772-86c8-840041bebb81'::uuid),('f9848f05-430b-4e5c-bdff-b8037f01f158'::uuid),('995b8db7-31d2-4db2-8cf1-f94e16560a9b'::uuid),('a8e09133-f283-4b58-82d9-cf93a57af5f8'::uuid),('ad2324fc-3d66-448c-8830-73ef2ce0d727'::uuid),('f4e4a3c8-cd52-4277-9a6e-9d6f6e69c706'::uuid)), calculated AS (SELECT tp.plan_id,COALESCE(sum(b.qty+COALESCE(a.adjustment_delta,0)),0) AS calculated_actual FROM target_plans tp LEFT JOIN public.inventory_transactions b ON b.delivery_plan_id=tp.plan_id AND b.tx_type='out' AND b.adjusted_from_transaction_id IS NULL AND b.deleted_at IS NULL LEFT JOIN LATERAL (SELECT COALESCE(sum(CASE WHEN adj.tx_type='adjust_in' THEN adj.qty WHEN adj.tx_type='adjust_out' THEN -adj.qty ELSE 0 END),0) AS adjustment_delta FROM public.inventory_transactions adj WHERE adj.adjusted_from_transaction_id=b.id AND adj.deleted_at IS NULL) a ON true GROUP BY tp.plan_id) SELECT p.plan_date,p.id AS plan_id,pr.sku,p.actual_qty AS stored_actual_qty,c.calculated_actual FROM calculated c JOIN public.delivery_plans p ON p.id=c.plan_id JOIN public.products pr ON pr.id=p.product_id WHERE p.actual_qty IS DISTINCT FROM c.calculated_actual ORDER BY p.plan_date DESC,pr.sku;
